3	import type { NetworkPresenceState } from "../../hooks/use-network-presence";
4	import { DetailComposer } from "../composer/detail-composer";
5	import { ConversationError } from "../empty-states/conversation-error";
6	import { DirectEmpty } from "../empty-states/direct-empty";
7	import { Timeline } from "../timeline/timeline";
8	import { MessageAvatar } from "../timeline/message-avatar";
9	import { WorkBanner } from "../work/work-banner";
10	import { useDirectRoomView } from "./use-direct-room-view";
11	
12	export interface DirectRoomProps {
13	  channel: string;
14	  directId: string;
15	  /** Used to render the *other* party's identity at the top per `_design.md` §5.6. */
16	  selfPeerId?: string;
17	}
18	
19	interface PresenceDotProps {
20	  state: NetworkPresenceState;
21	}
22	
23	function PresenceDot({ state }: PresenceDotProps) {
24	  if (state === "idle") {
25	    return null;
26	  }
27	
28	  const tone =
29	    state === "running"
30	      ? "var(--color-accent)"
31	      : state === "needs_input"
32	        ? "var(--color-warning)"
33	        : "var(--color-danger)";
34	
35	  const ariaLabel =
36	    state === "running" ? "running" : state === "needs_input" ? "needs input" : "errored";
37	
38	  return (
39	    <span
40	      aria-label={ariaLabel}
41	      className={cn(
42	        "ml-1 inline-block size-1.5 rounded-full",
43	        state === "running" && "motion-safe:animate-pulse"
44	      )}
45	      data-state={state}
46	      data-testid="network-direct-presence-dot"
47	      style={{ backgroundColor: tone }}
48	    />
49	  );
50	}
51	
52	export function DirectRoom({ channel, directId, selfPeerId }: DirectRoomProps) {
53	  const view = useDirectRoomView({ channel, directId, selfPeerId });
54	  const { room, session, disabledReason, openWork, handleRetry, handleDiscard } = view;
55	  const otherPeerId = room.otherPeerId;
56	  const detailError = room.detailError;
57	  const isResolvingDetail = !detailError && !room.detail;
58	
59	  return (
60	    <section
61	      aria-label={`Direct room with @${otherPeerId || "peer"}`}
62	      className="flex min-h-0 flex-1 flex-col"
63	      data-testid="network-direct-room"
64	    >
65	      <header
66	        className="flex h-12 items-center gap-3 border-b border-[color:var(--color-divider)] px-5"
67	        data-testid="network-direct-identity-row"
68	      >
69	        {otherPeerId ? (
70	          <MessageAvatar initialFrom={otherPeerId} seed={otherPeerId} sizePx={32} />
71	        ) : null}
72	        <div className="flex min-w-0 flex-1 items-center gap-2">
73	          <h1 className="truncate text-[16px] font-semibold text-[color:var(--color-text-primary)]">
74	            {otherPeerId ? `@${otherPeerId}` : "Direct room"}
75	          </h1>
76	          <span className="font-mono text-[10px] uppercase tracking-[0.06em] text-[color:var(--color-text-tertiary)]">
77	            agent
78	          </span>
79	          <PresenceDot state={room.presence.state} />
80	        </div>
81	      </header>
82	
83	      {detailError ? (
84	        <div className="flex flex-1 items-center justify-center px-5 py-10" role="alert">
85	          <ConversationError
86	            description={`Could not load direct room ${directId}. Choose an existing direct room from #${channel}.`}
87	            testId="network-direct-room-error"
88	            title="Direct room unavailable"
89	          />
90	        </div>
91	      ) : isResolvingDetail ? (
92	        <Timeline
93	          ariaLabel={`Direct messages with @${otherPeerId || "peer"}`}
94	          density="channel"
95	          isLoading
96	          messages={[]}
97	        />
98	      ) : (
99	        <>
100	          <WorkBanner hasNeedsInput={openWork.hasNeedsInput} openCount={openWork.openCount} />
101	
102	          <Timeline
103	            ariaLabel={`Direct messages with @${otherPeerId || "peer"}`}
104	            density="channel"
105	            emptyState={<DirectEmpty />}
106	            isLoading={room.isDetailLoading || room.isMessagesLoading}
107	            lastReadAt={room.lastReadIso}
108	            messages={room.messages}
109	            onDiscardOptimistic={handleDiscard}
110	            onRetryOptimistic={handleRetry}
111	          />
112	
113	          <DetailComposer
114	            channel={channel}
115	            directId={directId}
116	            disabledReason={disabledReason ?? undefined}
117	            displayName={session?.displayName}
118	            peerFrom={session?.peerId ?? ""}
119	            peerLabel={otherPeerId ? `@${otherPeerId}` : "@peer"}
120	            peerTo={otherPeerId || undefined}
121	            sessionId={session?.sessionId ?? ""}
122	            surface="direct"
123	          />
124	        </>
125	      )}
126	    </section>
127	  );
128	}
